import { useEffect, useRef, useState } from "react";
import base from "./pizza_base.png";

const TOPPINGS = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️", "🫑"];

const PRICES = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
  "🫑": 30,
};

const BASE_PRICE = 299;
const SIZE = 500;

export default function PizzaBuilder() {
  const canvasRef = useRef(null);

  const [selected, setSelected] = useState(TOPPINGS[0]);
  const [pizza, setPizza] = useState([]);

  function handlePizzaClick(e) {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();

    // Convert from screen coordinates to canvas coordinates.
    const x = ((e.clientX - rect.left) * SIZE) / rect.width;
    const y = ((e.clientY - rect.top) * SIZE) / rect.height;

    setPizza((pizza) => [...pizza, { topping: selected, x, y }]);
  }

	const image = new Image();
	image.src = base;

	useEffect(() => {
	const canvas = canvasRef.current;
	const ctx = canvas.getContext("2d");

	ctx.clearRect(0, 0, SIZE, SIZE);
	ctx.drawImage(image, 0, 0, SIZE, SIZE);

	ctx.font = "28px serif";
	ctx.textAlign = "center";
	ctx.textBaseline = "middle";

	pizza.forEach(({ topping, x, y }) => {
		ctx.fillText(topping, x, y);
	});
	}, [pizza]);

  const total =
    BASE_PRICE +
    pizza.reduce((sum, { topping }) => sum + PRICES[topping], 0);

  return (
    <main style={{ textAlign: "center" }}>
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{total}</h2>

      <p>
        {TOPPINGS.map((topping) => (
          <button
            key={topping}
            disabled={selected === topping}
            onClick={() => setSelected(topping)}
          >
            {topping}
          </button>
        ))}
      </p>

      <canvas
        ref={canvasRef}
        width={SIZE}
        height={SIZE}
        onClick={handlePizzaClick}
        style={{
          width: SIZE,
          maxWidth: "100%",
          height: "auto",
          cursor: "crosshair",
        }}
      />
    </main>
  );
}
